//! transformer-resonance-probe — DOES a TRANSFORMER's tail hidden (post-all-layers,
//! pre-lm_head, LAST prompt token) separate paraphrases from unrelated prompts — the
//! same semantic-key property validated for the rwkv7 SSM in `resonance-collision-probe`?
//!
//! This is the HONEST GATE for the transformer-mesh sovereign sieve. Everything
//! downstream — the native /generate `return_hidden` accessor (gnosis 02618367) and the
//! openai-server.ts sieve lane (724333ca) — rests on this being TRUE for transformers.
//! A NULL result is a real finding that blocks the transformer deploy.
//!
//! Transformer sibling of `resonance-collision-probe` (which does rwkv7/model_rwkv7):
//! this uses `NativeLlamaPipeline` (model.rs) with `forward_one` + `get_x_residual`
//! (the exact tail-hidden accessor the fat-station /generate return_hidden uses),
//! and a GPT-2 byte-level BPE tokenizer over the qwen vocab JSON (mirrors embed-text.rs).
//!
//! Same curated prompt set as the rwkv7 probe: 10 paraphrase GROUPS (g1..g10) x 3-5
//! phrasings + ~30 unrelated singletons. Fresh KV context (reset_context) per prompt so
//! state never leaks. Captures the LAST prompt token's `get_x_residual()` (= the sieve
//! key). Dumps labeled JSON incrementally (survive a reap under machine contention),
//! SAME shape as the rwkv7 dump so the existing analysis scripts read it unchanged.
//!
//! Run:  ./transformer-resonance-probe <knot_path> <qwen_vocab_json> [out_json]

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;
use std::collections::HashMap;
use std::fs;

// ---- GPT-2 byte-level BPE tokenizer over the qwen vocab JSON (mirrors embed-text.rs) ----
// The qwen vocab JSON maps token-STRING -> id under a top-level ".vocab" object. GPT-2
// byte-level pre-tokenization maps each raw UTF-8 byte to a printable "byte char"; the
// word-start marker is 'Ġ' (U+0120). We greedy longest-prefix match over the byte-char
// stream. This is a pragmatic encoder (no learned merge ranks) but is adequate for the
// separation measurement — the exact token boundaries matter far less than that
// paraphrases-vs-unrelated are tokenized consistently.

fn load_vocab(path: &str) -> Result<HashMap<String, u32>, String> {
    let s = fs::read_to_string(path).map_err(|e| format!("vocab read {}: {}", path, e))?;
    let v: serde_json::Value = serde_json::from_str(&s).map_err(|e| format!("vocab json: {}", e))?;
    let obj = v
        .get("vocab")
        .and_then(|x| x.as_object())
        .ok_or("vocab json has no .vocab object")?;
    let mut m = HashMap::with_capacity(obj.len());
    for (k, val) in obj {
        if let Some(id) = val.as_u64() {
            m.insert(k.clone(), id as u32);
        }
    }
    Ok(m)
}

/// GPT-2 byte-to-unicode table: every byte 0..256 maps to a printable char so the BPE
/// vocab keys (which are in this "byte char" space) can be matched. Standard mapping.
fn byte_to_unicode() -> HashMap<u8, char> {
    let mut bs: Vec<u32> = Vec::new();
    for b in b'!'..=b'~' {
        bs.push(b as u32);
    }
    for b in 0xA1u32..=0xAC {
        bs.push(b);
    }
    for b in 0xAEu32..=0xFF {
        bs.push(b);
    }
    let mut cs: Vec<u32> = bs.clone();
    let mut n = 0u32;
    for b in 0u32..256 {
        if !bs.contains(&b) {
            bs.push(b);
            cs.push(256 + n);
            n += 1;
        }
    }
    let mut map = HashMap::new();
    for (b, c) in bs.iter().zip(cs.iter()) {
        map.insert(*b as u8, char::from_u32(*c).unwrap());
    }
    map
}

/// Encode text -> token ids. Byte-level: convert the raw UTF-8 bytes of the text (with a
/// leading space so the first word gets its 'Ġ' word-start marker, GPT-2 convention) into
/// the byte-char stream, then greedy longest-prefix match against the vocab.
fn encode(text: &str, vocab: &HashMap<String, u32>, b2u: &HashMap<u8, char>) -> Vec<u32> {
    // Leading space => first token carries the word-start marker, matching how the prompt
    // would appear mid-stream. GPT-2/qwen tokenize " The" not "The" for a sentence start
    // in practice within a running document; a leading space is the closest single-prompt
    // approximation and keeps all prompts consistent.
    let with_space = format!(" {}", text);
    let byte_chars: String = with_space.bytes().map(|b| b2u[&b]).collect();
    let chars: Vec<char> = byte_chars.chars().collect();
    let mut ids: Vec<u32> = Vec::new();
    let mut i = 0usize;
    while i < chars.len() {
        let maxlen = (chars.len() - i).min(64);
        let mut matched = false;
        for len in (1..=maxlen).rev() {
            let cand: String = chars[i..i + len].iter().collect();
            if let Some(&id) = vocab.get(&cand) {
                ids.push(id);
                i += len;
                matched = true;
                break;
            }
        }
        if !matched {
            // single byte-char fallback: try the single char as a token, else skip.
            let single: String = chars[i..i + 1].iter().collect();
            if let Some(&id) = vocab.get(&single) {
                ids.push(id);
            }
            i += 1;
        }
    }
    ids
}

fn main() -> Result<(), String> {
    let mut args = std::env::args().skip(1);
    let knot_path = args
        .next()
        .unwrap_or_else(|| "/tmp/qwen-0.5b.knot".to_string());
    let vocab_path = args.next().unwrap_or_else(|| {
        "/Users/buley/Documents/Code/monorepo/apps/edge-workers/vocab-cache/qwen3-8b-temp-vocab.json"
            .to_string()
    });
    let out_path = args.next().unwrap_or_else(|| {
        "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/transformer_acts_qwen05b.json".to_string()
    });

    // SAME curated set as resonance-collision-probe.rs (rwkv7). Paraphrase groups g*,
    // unrelated singletons u_*.
    let prompts: Vec<(&str, &str)> = vec![
        // --- g1: capital of France (Paris) ---
        ("g1_paris", "The capital of France is"),
        ("g1_paris", "France's capital city is"),
        ("g1_paris", "The largest city and capital of France is"),
        ("g1_paris", "What is the capital of France? It is"),
        ("g1_paris", "The French capital is the city of"),
        // --- g2: 2 + 2 = 4 ---
        ("g2_math", "Two plus two equals"),
        ("g2_math", "The sum of 2 and 2 is"),
        ("g2_math", "If you add two and two you get"),
        ("g2_math", "2 + 2 ="),
        ("g2_math", "Adding two to two gives"),
        // --- g3: color of a clear sky (blue) ---
        ("g3_sky", "The sky on a clear day is the color"),
        ("g3_sky", "On a sunny day the sky appears"),
        ("g3_sky", "Looking up on a cloudless day the sky is"),
        ("g3_sky", "The color of a clear daytime sky is"),
        // --- g4: freezing point of water (0C / 32F) ---
        ("g4_freeze", "Water freezes at a temperature of"),
        ("g4_freeze", "The freezing point of water is"),
        ("g4_freeze", "Water turns to ice at"),
        ("g4_freeze", "At what temperature does water freeze? At"),
        // --- g5: photosynthesis (definition) ---
        ("g5_photo", "Photosynthesis is the process by which plants"),
        ("g5_photo", "Plants make food from sunlight through a process called"),
        ("g5_photo", "The way green plants convert sunlight into energy is"),
        ("g5_photo", "Using light, plants produce sugar in a process known as"),
        // --- g6: boiling point of water (100C) ---
        ("g6_boil", "Water boils at a temperature of"),
        ("g6_boil", "The boiling point of water is"),
        ("g6_boil", "Water turns to steam at"),
        ("g6_boil", "At sea level water starts to boil at"),
        // --- g7: capital of Japan (Tokyo) ---
        ("g7_tokyo", "The capital of Japan is"),
        ("g7_tokyo", "Japan's capital city is"),
        ("g7_tokyo", "The largest city and capital of Japan is"),
        ("g7_tokyo", "The Japanese capital is the city of"),
        // --- g8: gravity (why things fall) ---
        ("g8_gravity", "When you drop an object it falls because of"),
        ("g8_gravity", "The force that pulls objects toward the earth is"),
        ("g8_gravity", "Things fall to the ground due to"),
        ("g8_gravity", "What makes apples fall from trees is"),
        // --- g9: recursive fibonacci (code) ---
        ("g9_fib", "def fibonacci(n): return"),
        ("g9_fib", "The recursive function for fibonacci numbers returns"),
        ("g9_fib", "To compute fibonacci recursively you write fib(n) ="),
        ("g9_fib", "A recursive fib function returns fib(n-1) plus"),
        // --- g10: mitochondria (definition) ---
        ("g10_mito", "The mitochondria is the"),
        ("g10_mito", "The powerhouse of the cell is the"),
        ("g10_mito", "The organelle that produces energy in cells is the"),
        ("g10_mito", "Cells generate ATP energy using an organelle called the"),
        // --- ~30 NOVEL / unrelated singletons ---
        ("u_earnings", "The quarterly earnings report showed"),
        ("u_story", "Once upon a time there was a"),
        ("u_pasta", "The best way to cook pasta is to"),
        ("u_moon", "In 1969 astronauts first landed on"),
        ("u_market", "The stock market closed higher today after"),
        ("u_door", "She opened the door and saw"),
        ("u_recipe", "The recipe calls for two cups of"),
        ("u_movie", "My favorite movie of all time is"),
        ("u_forecast", "The weather forecast for tomorrow predicts"),
        ("u_guitar", "He picked up the guitar and began to"),
        ("u_rome", "The ancient Roman empire was known for"),
        ("u_tire", "To change a flat tire you first"),
        ("u_novel", "The novel begins with a description of"),
        ("u_invest", "Investors are worried about rising"),
        ("u_dog", "The dog ran across the yard chasing"),
        ("u_diet", "A balanced diet should include plenty of"),
        ("u_concert", "The concert was sold out within"),
        ("u_meeting", "During the meeting they discussed the"),
        ("u_paint", "The painting depicts a scene of"),
        ("u_climate", "Climate scientists warn that global"),
        ("u_train", "The train departs from platform"),
        ("u_bread", "In order to bake bread you need"),
        ("u_game", "The championship game ended with a score of"),
        ("u_photo", "Photographers often prefer shooting during the"),
        ("u_phone", "The new smartphone features a larger"),
        ("u_grad", "After graduation she decided to"),
        ("u_river", "The river flows gently through the"),
        ("u_python", "Programming languages like Python are"),
        ("u_museum", "The museum's newest exhibit features"),
        ("u_traffic", "Traffic was heavy on the highway during"),
    ];

    eprintln!("transformer-resonance-probe: knot={knot_path}");
    let b2u = byte_to_unicode();
    let vocab = load_vocab(&vocab_path)?;
    eprintln!("[probe] vocab {} entries", vocab.len());

    let knot = KnotWeights::load(&knot_path).map_err(|e| format!("knot load: {:?}", e))?;
    // Load once; reset_context() between prompts (KV overwritten, causal attn reads [0,pos]).
    let mut pipe = NativeLlamaPipeline::from_knot(knot, false, 0.8);
    let d = pipe.hidden_dim();
    eprintln!(
        "[probe] hidden_dim={} layers={} vocab_size={}",
        d,
        pipe.num_layers(),
        pipe.vocab_size()
    );

    let mut records: Vec<serde_json::Value> = Vec::new();
    let dump = |records: &Vec<serde_json::Value>| {
        let out = serde_json::json!({
            "hidden_dim": d,
            "note": "TRANSFORMER (qwen2.5-0.5b NativeLlamaPipeline) final pre-lm_head hidden (get_x_residual) of the LAST prompt token",
            "records": records,
        });
        fs::write(&out_path, serde_json::to_vec(&out).unwrap()).expect("write json");
    };

    for (group, text) in &prompts {
        let tokens = encode(text, &vocab, &b2u);
        if tokens.is_empty() {
            eprintln!("  [{group}] \"{text}\" -> EMPTY tokenization, skipping");
            continue;
        }
        pipe.reset_context();
        for (pos, &tok) in tokens.iter().enumerate() {
            pipe.forward_one(tok as usize, pos, false)
                .map_err(|e| format!("forward_one({}, {}): {}", tok, pos, e))?;
        }
        // LAST prompt token's tail hidden = the sieve key.
        let last: Vec<f32> = pipe.get_x_residual().to_vec();
        let argmax = pipe
            .get_logits()
            .iter()
            .enumerate()
            .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
            .map(|(i, _)| i)
            .unwrap_or(0);
        eprintln!(
            "  [{group}] \"{text}\" -> {} tokens {:?} nextTok={}",
            tokens.len(),
            tokens,
            argmax
        );
        records.push(serde_json::json!({
            "group": group,
            "text": text,
            "tokens": tokens,
            "next_token_id": argmax,
            "activation": last,
        }));
        dump(&records);
    }

    dump(&records);
    eprintln!("\nwrote {} records x {} dims to {out_path}", records.len(), d);
    Ok(())
}
